169→
170→/* Shimmer skeleton animation */
171→@keyframes shimmer {
172→  0% { background-position: -200% 0; }
173→  100% { background-position: 200% 0; }
174→}
175→.skeleton-shimmer {
176→  background: linear-gradient(90deg, rgba(255,255,255,0.03) 25%, rgba(255,255,255,0.06) 50%, rgba(255,255,255,0.03) 75%);
